const topic = $.input.topic || '';
const query = 'trending social media posts ' + topic + ' viral engagement';
return { query };

const topic = $.input.topic;
const platforms = $.input.platforms || 'Twitter, LinkedIn, Instagram';
const tone = $.input.tone || 'professional yet engaging';
const results = $.steps.researchTrends.response.results || [];
let trends = '';
results.forEach((r, i) => { trends += (i + 1) + '. ' + (r.title || r.url) + ': ' + (r.text || '').slice(0, 150) + '
'; });

const prompt = 'You are an expert social media content strategist. Generate optimized posts for multiple platforms.

TOPIC: ' + topic + '
PLATFORMS: ' + platforms + '
TONE: ' + tone + '

TRENDING INSIGHTS:
' + trends + '

Return ONLY valid JSON:
{
  "posts": [
    {
      "platform": "Twitter",
      "content": "post text optimized for this platform",
      "hashtags": ["#tag1"],
      "characterCount": 0,
      "bestTimeToPost": "suggested posting time",
      "imagePrompt": "AI image generation prompt for visual",
      "engagementTip": "tip to boost engagement"
    }
  ],
  "contentPillar": "overarching content theme",
  "crossPlatformStrategy": "how posts work together across platforms"
}';

return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { posts: [], contentPillar: raw.slice(0, 200) }; }

const ai = $.steps.parseAI.output;
const posts = ai.posts || [];
const date = new Date().toISOString().split('T')[0];
const rows = posts.map(p => [
  date,
  p.platform || '',
  $.input.topic,
  p.content || '',
  (p.hashtags || []).join(' '),
  p.bestTimeToPost || '',
  'Draft'
]);
return { rows, postCount: posts.length };

const ai = $.steps.parseAI.output;
const posts = ai.posts || [];
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Social Media Content for Review', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Topic:* ' + $.input.topic + '\n*Theme:* ' + (ai.contentPillar || 'N/A') } });
blocks.push({ type: 'divider' });

posts.forEach(p => {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + p.platform + ':*\n' + (p.content || '').slice(0, 1500) + '\n' + (p.hashtags || []).join(' ') } });
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Best time: ' + (p.bestTimeToPost || 'N/A') + ' | ' + (p.engagementTip || '') }] });
});

if (ai.crossPlatformStrategy) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Strategy:* ' + ai.crossPlatformStrategy } });
}

const fallback = 'Social content ready: ' + posts.length + ' posts for ' + $.input.topic;
return { blocks, fallback };
